from agent import *from models.products import *import reXCAT = ['Bazar', 'Akce']def serialize_text(text):    text = re.sub(r'&([a-zA-Z]+);', lambda match: '&' + match.group(1).lower() + ';', text).replace('<br />', ' ').replace('<br/>', ' ').replace('<br/', ' ').replace("\r", "").replace("\n", "").replace('\t', '').replace('&', '&').replace('°', '°').replace('œ', 'œ').replace('í', 'í').replace('ú', 'ú').replace('“', '"').replace('£', '£').replace('"', '"').replace('à', 'à').replace('é', 'é').replace('á', 'á').replace('´', '́').replace('ã', 'ã').replace('ç', 'ç').replace('ó', 'ó').replace('€', '€').replace('ê', 'ê').replace('è', 'è').replace('’', '’').replace('”', '”').replace(' ', ' ').replace('<', '<').replace('>', '>').replace('‘', '‘').replace('–', '–').replace('ä', 'ä').replace('ß', 'ß').replace('ö', 'ö').replace('ü', 'ü').replace('â', 'â').replace('õ', 'õ').replace('ø', 'ø').replace('…', '…').replace('„', '„').replace('—', '—')    return textdef remove_emoji(string):    emoji_pattern = re.compile("["                               u"\U0001F600-\U0001F64F"  # emoticons                               u"\U0001F300-\U0001F5FF"  # symbols & pictographs                               u"\U0001F680-\U0001F6FF"  # transport & map symbols                               u"\U0001F1E0-\U0001F1FF"  # flags (iOS)                               u"\U00002500-\U00002BEF"  # chinese char                               u"\U00002702-\U000027B0"                               u"\U00002702-\U000027B0"                               u"\U000024C2-\U0001F251"                               u"\U0001f926-\U0001f937"                               u"\U00010000-\U0010ffff"                               u"\u2640-\u2642"                               u"\u2600-\u2B55"                               u"\u200d"                               u"\u23cf"                               u"\u23e9"                               u"\u231a"                               u"\ufe0f"  # dingbats                               u"\u3030"                               "]+", flags=re.UNICODE)    return emoji_pattern.sub(r'', string)def strip_namespace(data):    tmp = data.content_file + ".tmp"    out = file(tmp, "w")    for line in file(data.content_file):        line = line.replace('<ns0', '<')        line = line.replace('ns0:', '')        line = line.replace(' xmlns', ' abcde=')        out.write(line + "\n")    out.close()    os.rename(tmp, data.content_file)def run(context, session):    session.browser.use_new_parser = True    session.sessionbreakers = [SessionBreak(max_requests=10000)]    session.queue(Request('https://www.megapixel.cz/eshop'), process_catlist, dict())def process_catlist(data, context, session):    strip_namespace(data)    cats1 = data.xpath('//div[h1[contains(., "E-shop Megapixel")]]/h2')    for cat1 in cats1:        name1 = cat1.xpath('a/text()').string()        if name1 not in XCAT:            cats2 = cat1.xpath('following-sibling::section[1]//section/a')            for cat2 in cats2:                name2 = cat2.xpath('.//h3/text()').string()                url = cat2.xpath('@href').string()                session.queue(Request(url), process_prodlist, dict(cat=name1+'|'+name2))def process_prodlist(data, context, session):    strip_namespace(data)    prods = data.xpath('//div[@id="products"]//a[contains(@class, "product-box__link")]')    for prod in prods:        name = prod.xpath('.//h4/text()').string()        url = prod.xpath('@href').string()        revs_cnt = prod.xpath('.//span[@class="rating__count"]/text()').string()        if revs_cnt:            revs_cnt = int(revs_cnt.strip('( ×)'))            if revs_cnt > 0:                session.queue(Request(url), process_product, dict(context, name=name, url=url))    next_url = data.xpath('//a[contains(@class, "paging__btn-next")]/@href').string()    if next_url:        session.queue(Request(next_url), process_prodlist, dict(context))def process_product(data, context, session):    strip_namespace(data)    product = Product()    product.name = context['name']    product.manufacturer = data.xpath('//meta[@property="og:brand"]/@content').string()    product.url = context['url']    product.category = context['cat']    product.ssid = data.xpath('//textarea[@id="product-detail-id"]/text()').string()    product.sku = product.ssid    mpn = data.xpath('//textarea[@id="product-detail-pn"]/text()').string()    if mpn and len(mpn) > 4:        product.properties.append(ProductProperty(type='id.manufacturer', value=mpn))    session.do(Request(product.url+'/recenze'), process_reviews, dict(product=product))    if product.reviews:        session.emit(product)def process_reviews(data, context, session):    strip_namespace(data)    product = context['product']    revs = data.xpath('//div[contains(@class, "comment-list__item")]')    for rev in revs:        review = Review()        review.type = 'user'        review.url = product.url        review.date = rev.xpath('.//meta[@itemprop="datePublished"]/@content').string()        author = ''        author_date = rev.xpath('.//p[contains(@class, "author-content")]//text()').string(multiple=True)        if author_date:            if 'Ověřený zákazník' in author_date:                review.add_property(type='is_verified_buyer', value=True)            review.date = author_date.split(',')[-1].strip()            author = author_date.split('Ověřený zákazník')[-1].split('produkt zakoupili.')[-1].split(',')[0].strip()            author = remove_emoji(serialize_text(author)).strip()            if author:                review.authors.append(Person(name=author, ssid=author))        grade_overall = rev.xpath('.//span[@class="sr-only"]/text()').string()        if grade_overall:            review.grades.append(Grade(type="overall", value=float(grade_overall), best=5.0))        excerpt = rev.xpath('div[@class="comment__text"]/p/text()').string(multiple=True)        if excerpt:            excerpt = remove_emoji(serialize_text(excerpt)).strip()            if excerpt:                review.properties.append(ReviewProperty(type="excerpt", value=excerpt))                review.ssid = review.digest() if author else review.digest(excerpt)                product.reviews.append(review)